import{_ as i,o as t,c as r,a2 as n}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Process & Validation","description":"","frontmatter":{"title":"Process & Validation"},"headers":[],"relativePath":"docs/fr/advertisers/display-email/workflow.md","filePath":"docs/fr/advertisers/display-email/workflow.md"}'),s={name:"docs/fr/advertisers/display-email/workflow.md"};function a(o,e,l,d,p,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="workflow-de-campagne" tabindex="-1">Workflow de campagne <a class="header-anchor" href="#workflow-de-campagne" aria-label="Permalink to &quot;Workflow de campagne&quot;">​</a></h1><p>Le déploiement d&#39;un encart newsletter est rapide. Voici les étapes de la soumission à la diffusion.</p><hr class="my-6"><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">1</div><div><h3 class="mt-0 text-blue-200">Envoi des éléments</h3><p>L&#39;Annonceur fournit les éléments créatifs au Distributeur (via getinside ou en direct selon le canal défini) :</p><ul><li><strong>Le Visuel :</strong> Une image (JPG, PNG ou GIF) respectant les spécifications.</li><li><strong>Le Lien de destination :</strong> L&#39;URL de la Landing Page vers laquelle renvoyer le trafic.</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">2</div><div><h3 class="mt-0 text-purple-200">Configuration du Tracking</h3><p>L&#39;équipe <strong>getinside</strong> intervient pour rendre la campagne mesurable :</p><div style="background:var(--gi-tint-blue-bg);border:1px solid var(--vp-c-divider);padding:15px;border-radius:6px;"><ol class="mb-0 pl-4"><li>Nous générons un <strong>lien de redirection tracké</strong> (<code>gtinsi.de</code>).</li><li>Ce lien est transmis au Distributeur.</li><li>C&#39;est ce lien unique qui permettra de compter les clics.</li></ol></div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">3</div><div><h3 class="mt-0 text-blue-200">Intégration et Validation (BAT)</h3><p>Le Distributeur intègre votre image dans sa newsletter.</p><ul><li>Il vous envoie un <strong>BAT</strong> (Bon à Tirer) ou un lien de prévisualisation.</li><li><strong>Action requise :</strong> Vérifiez le rendu (notamment sur mobile) et cliquez sur le bouton <strong>&quot;Valider la campagne&quot;</strong> dans votre espace <a href="https://app.getinside.media/">app.getinside.media</a>.</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-tint-green-text);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">🚀</div><div><h3 class="mt-0 text-green-200">Diffusion</h3><p>Une fois les deux validations enregistrées (Annonceur + Distributeur), la newsletter est envoyée à la date prévue.</p></div></div>',7)])])}const f=i(s,[["render",a]]);export{g as __pageData,f as default};
